import java.util.*;

class TodoList {
    private static class Task {
        int id;
        String description;
        int dueDate;
        List<String> tags;
        boolean completed;

        public Task(int id, String description, int dueDate, List<String> tags) {
            this.id = id;
            this.description = description;
            this.dueDate = dueDate;
            this.tags = tags;
            this.completed = false;
        }
    }

    private int taskId;
    private Map<Integer, List<Task>> tasks;

    public TodoList() {
        taskId = 1;
        tasks = new HashMap<>();
    }

    public int addTask(int userId, String taskDescription, int dueDate, List<String> tags) {
        tasks.computeIfAbsent(userId, k -> new ArrayList<>());
        tasks.get(userId).add(new Task(taskId, taskDescription, dueDate, tags));
        return taskId++;
    }

    public List<String> getAllTasks(int userId){
        List<String> res = new ArrayList<>();
        List<Task> userTasks = tasks.getOrDefault(userId, new ArrayList<>());

        Collections.sort(userTasks, Comparator.comparingInt(a -> a.dueDate));

        for (Task task : userTasks) {
            if (!task.completed) {
                res.add(task.description);
            }
        }

        return res;
    }

    public List<String> getTasksForTag(int userId, String tag){
        List<String> res = new ArrayList<>();
        List<Task> userTasks = tasks.getOrDefault(userId, new ArrayList<>());

        Collections.sort(userTasks, Comparator.comparingInt(a -> a.dueDate));

        for (Task task : userTasks) {
            if (!task.completed && task.tags.contains(tag)) {
                res.add(task.description);
            }
        }

        return res;
    }

    public void completeTask(int userId, int taskId){
        List<Task> userTasks = tasks.getOrDefault(userId, new ArrayList<>());
        for (Task task : userTasks) {
            if (task.id == taskId) {
                task.completed = true;
                break;
            }
        }
    }
}
